mongoURI := config.GetEnvOrDefault("MONGO_URI", "mongodb://localhost:27017")
mongoDatabase := config.GetEnvOrDefault("MONGO_DATABASE", "app")

mongoClient, err := mongo.New(mongo.Config{
	URI:      mongoURI,
	Database: mongoDatabase,
	Logger:   appLogger,
})
if err != nil {
	appLogger.Error("failed to start app: %v", err)
}
defer mongoClient.Close()
app.RegisterHealthChecker(mongo.NewHealthChecker(mongoClient))
